Code.Terraform:
```hcl
# OpenSearch ドメインに対して AUDIT_LOGS を有効にする
resource "aws_opensearch_domain" "example" {
  domain_name = "<example_resource_name>"

  log_publishing_options {
    log_type                 = "AUDIT_LOGS"
    cloudwatch_log_group_arn = "<CLOUDWATCH_LOG_GROUP_ARN>"  # 重要: 監査ログの送信先
    enabled                  = true                           # 重要: チェックを通過するために AUDIT_LOGS をオンにする
  }
}
```
